int main()

{

  int N, x;



  cin >> N >> x;





  int bottom = 2 * N - 1;

  deque< int > val;

  bool used[500001] = {};



  if(2 <= x && x + 2 <= bottom) {

    val.push_back(x + 1);

    used[x + 1] = true;

    val.push_back(x);

    used[x] = true;

    val.push_back(x - 1);

    used[x - 1] = true;

    val.push_back(x + 2);

    used[x + 2] = true;





  } else if(1 <= x - 2 && x + 1 <= bottom) {

    val.push_back(x - 1);

    used[x - 1] = true;

    val.push_back(x);

    used[x] = true;

    val.push_back(x + 1);

    used[x + 1] = true;

    val.push_back(x - 2);

    used[x - 2] = true;

  }





  if(val.empty()) {

    if(N == 2 && x == 2) {

      cout << "Yes" << endl;

      cout << "1" << endl;

      cout << "2" << endl;

      cout << "3" << endl;

    } else {

      cout << "No" << endl;

    }

  } else {

    bool first = false;

    int left = bottom / 2 - 1;

    for(int i = 1; i <= bottom; i++) {

      if(!used[i]) {

        --left;

        if(left >= 0) val.push_front(i);

        else val.push_back(i);

      }

    }



    cout << "Yes" << endl;

    for(int v : val) {

      cout << v << endl;

    }

  }

}

